module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

reg [1:0] state;
reg [1:0] next_state;

always @(*) begin
    case (state)
        s0: next_state = (data_in == 1'b0) ? s1 : s0;
        s1: next_state = (data_in == 1'b1) ? s2 : s1;
        s2: next_state = (data_in == 1'b0) ? s3 : s0;
        s3: next_state = (data_in == 1'b1) ? s2 : s1;
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= s0;
    end else begin
        state <= next_state;
    end
end

assign data_out = (state == s2) && (data_in == 1'b0);

endmodule
